import sys

def gcd(a, b):
    while b:
        a, b = b, a % b
    return abs(a)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        g = 0
        pos = neg = False
        for _ in range(N):
            x = int(next(it))
            if x > 0:
                pos = True
            if x < 0:
                neg = True
            g = gcd(g, abs(x))
        if g == 0:
            ans = 0
        elif pos and neg:
            ans = 2 * g
        else:
            ans = g
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

